const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
const message = (body.message || '').toString().trim();
if (!message) return { json: { ok: false, status: 400, error: 'Missing message' } };
if (message.length > 4000) return { json: { ok: false, status: 400, error: 'Message too long (max 4000 chars)' } };
return { json: { token, message } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.id || rows.user_id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
return { json: { ok: true, user_id: row.user_id || row.id } };

const raw = $input.item.json;
let sessionId = null;
if (typeof raw === 'string') sessionId = raw.replace(/"/g, '');
else if (Array.isArray(raw) && raw.length) sessionId = raw[0];
else if (raw && raw.find_or_create_active_chat_session) sessionId = raw.find_or_create_active_chat_session;
if (!sessionId) return { json: { ok: false, status: 500, error: 'Could not resolve chat session' } };
return { json: { session_id: sessionId } };

// Build initial Anthropic request body with tools defined.
// Tools mirror the MCP Tool Gateway's 10-tool surface.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const history = allOf('Load History');

const systemPrompt = [
  'You are the Crystallux Assistant — Mary\'s in-app helper. You have access to platform tools that can read live data (leads, pipeline, system health, market signals). When the user asks something that needs data, USE the tools instead of guessing.',
  '',
  'Tool-use rules:',
  '- Use a tool when the answer requires live data (counts, recent activity, system status). Do NOT use tools for general platform questions you can answer from context.',
  '- After calling tools, summarize the result in plain words. Do not dump raw JSON.',
  '- If a tool returns empty or fails, acknowledge it honestly. Do not invent data.',
  '- For write actions (sending email, creating booking) — note that write tools are not enabled yet, will land in a follow-up.',
  '',
  'About Crystallux:',
  '- Sales operating system with multi-vertical Smart Quote (7 industries) + MAXI (21 SMB industries) + MGA insurance vertical.',
  '- Avatars: LUXI (live commerce), AVA (insurance education), MAXI (SMB growth), CIRO (operations), MGA.',
  '- Sentinel monitors cost / health / security / comms delivery.',
  '- Market Intelligence ingests external signals (news, weather, regulatory) and auto-tunes campaign multipliers.',
  '',
  'Style: concise, direct, no fluff, no em-dashes. Max 200 words unless the user asks for detail.'
].join('\n');

const tools = [
  {
    name: 'check_system_health',
    description: 'Returns platform KPIs: total leads, active clients, bookings this week, errors 24h, MRR. Use for any "how are we doing" question.',
    input_schema: { type: 'object', properties: {}, required: [] }
  },
  {
    name: 'check_pipeline_health',
    description: 'Returns the Sales Engine pipeline health: leads by stage, outreach throughput, conversion rates. Use for pipeline-specific questions.',
    input_schema: { type: 'object', properties: {}, required: [] }
  },
  {
    name: 'get_pipeline_stats',
    description: 'Returns the pipeline statistics: counts by lead_status, by source, by industry. Use when user wants a breakdown.',
    input_schema: { type: 'object', properties: {}, required: [] }
  },
  {
    name: 'list_leads',
    description: 'Lists leads with optional filters. Use when user wants to see specific leads.',
    input_schema: { type: 'object', properties: {
      status: { type: 'string', description: 'Filter by lead_status (e.g. "New Lead", "Booked", "Replied")' },
      industry: { type: 'string', description: 'Filter by industry' },
      city: { type: 'string', description: 'Filter by city' },
      limit: { type: 'integer', description: 'Max rows (default 20, max 100)' }
    }, required: [] }
  },
  {
    name: 'get_lead',
    description: 'Fetch full detail for a single lead by id. Use when user asks about a specific lead.',
    input_schema: { type: 'object', properties: {
      lead_id: { type: 'string', description: 'UUID of the lead' }
    }, required: [] }
  },
  {
    name: 'research_lead',
    description: 'Run enrichment + research on a lead via Apollo + behavioral signals. Returns a full intelligence profile.',
    input_schema: { type: 'object', properties: {
      lead_id: { type: 'string', description: 'UUID of the lead to research' }
    }, required: ['lead_id'] }
  },
  {
    name: 'score_lead',
    description: 'Compute the priority + buy-signal score for a lead. Returns score + signal flags + recommended next action.',
    input_schema: { type: 'object', properties: {
      lead_id: { type: 'string', description: 'UUID of the lead to score' }
    }, required: ['lead_id'] }
  },
  {
    name: 'update_lead_status',
    description: 'Move a lead to a new pipeline stage. Valid statuses include: New Lead, Outreach Ready, Replied, Booked, Cold, Closed.',
    input_schema: { type: 'object', properties: {
      lead_id: { type: 'string', description: 'UUID of the lead' },
      lead_status: { type: 'string', description: 'New status to set' }
    }, required: ['lead_id', 'lead_status'] }
  },
  {
    name: 'scan_city',
    description: 'Trigger a city scan to discover new leads in a given city + industry. Returns the scan_id and expected lead count.',
    input_schema: { type: 'object', properties: {
      city: { type: 'string', description: 'City to scan (e.g. "Toronto", "Vancouver")' },
      industry: { type: 'string', description: 'Industry vertical to target' }
    }, required: ['city', 'industry'] }
  },
  {
    name: 'get_execution_stats',
    description: 'Returns workflow execution stats: counts by status, recent failures, throughput. Use for ops-health questions.',
    input_schema: { type: 'object', properties: {}, required: [] }
  }
];

const messages = history.filter(function (m) {
  return m && m.content && (m.role === 'user' || m.role === 'assistant');
}).map(function (m) {
  return { role: m.role, content: String(m.content).slice(0, 4000) };
});

return { json: {
  payload: {
    model: 'claude-sonnet-4-6',
    max_tokens: 2048,
    system: systemPrompt,
    tools: tools,
    messages: messages
  }
} };

// Execute tool-use loop. Up to 3 iterations of tool calls before
// forcing Claude to return a text response.
const PUBLIC_BASE = 'https://automation.crystallux.org/webhook';
const MCP_KEY = $env.MCP_API_KEY || 'crystallux-mcp-internal-key';
const MAX_ITERATIONS = 3;

let response = $input.first().json;
let payload  = $('Build Claude Request').first().json.payload;

const toolCallsLog = [];
let iterations = 0;

async function callMcp(toolName, toolInput) {
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: PUBLIC_BASE + '/crystallux-mcp',
      headers: {
        'X-MCP-API-Key': MCP_KEY,
        'Content-Type': 'application/json'
      },
      body: { tool_name: toolName, tool_input: toolInput || {} },
      json: true,
      timeout: 30000
    });
    return r;
  } catch (e) {
    return { ok: false, error: e.message || String(e) };
  }
}

async function callClaude(p) {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'anthropic-version': '2023-06-01',
      'Content-Type': 'application/json',
      'x-api-key': $env.ANTHROPIC_API_KEY || ''
    },
    body: p,
    json: true,
    timeout: 45000
  });
  return r;
}

// Bind helpers context
const boundCallMcp = callMcp.bind(this);
const boundCallClaude = callClaude.bind(this);

while (response && response.stop_reason === 'tool_use' && iterations < MAX_ITERATIONS) {
  iterations++;
  const toolUses = (response.content || []).filter(function (b) { return b && b.type === 'tool_use'; });
  if (!toolUses.length) break;

  // Execute tools in series (could parallelize but easier to debug serial)
  const toolResults = [];
  for (const tu of toolUses) {
    const result = await boundCallMcp(tu.name, tu.input);
    toolCallsLog.push({ name: tu.name, input: tu.input, result: result });
    toolResults.push({
      type: 'tool_result',
      tool_use_id: tu.id,
      content: JSON.stringify(result).slice(0, 6000)
    });
  }

  // Append the assistant turn and user turn (with tool results)
  payload.messages.push({ role: 'assistant', content: response.content });
  payload.messages.push({ role: 'user', content: toolResults });

  // Call Claude again
  if ($env.ANTHROPIC_API_KEY) {
    response = await boundCallClaude(payload);
  } else {
    // Fallback: if env var isn't available in Code node, the loop can't
    // continue (Anthropic credential is on the httpRequest node, not here).
    // In that case, surface what tools ran and stop.
    break;
  }
}

const textBlock = (response.content || []).find(function (b) { return b && b.type === 'text'; });
const finalText = textBlock ? textBlock.text : '(Claude returned no text — tool loop may have stopped early.)';

return { json: {
  response: finalText,
  model: response.model || null,
  stop_reason: response.stop_reason || null,
  usage: response.usage || null,
  tool_calls: toolCallsLog,
  iterations: iterations
} };

const r = $('Tool Loop + Final Answer').first().json;
const sess = $('Normalize Session').first().json;
return { json: { ok: true, data: {
  response: r.response,
  session_id: sess.session_id,
  tool_calls: r.tool_calls,
  iterations: r.iterations,
  model: r.model,
  stop_reason: r.stop_reason,
  usage: r.usage
} } };
